import Foundation

/// Deterministic point-selection output for one skinning component encoder branch.
public struct SmeltPointSelection: Sendable, Equatable {
    /// Source-row indices in farthest-point order.
    public let sourceIndices: [Int]
    /// Interleaved point/normal rows matching `sourceIndices`.
    public let pointNormals: [Float]

    public init(sourceIndices: [Int], pointNormals: [Float]) {
        self.sourceIndices = sourceIndices
        self.pointNormals = pointNormals
    }
}

/// Source-faithful deterministic eval selection for the skinning component's point encoders.
///
/// Candidate tables are the exact little-endian UInt32 output of NumPy 2.4.4's
/// PCG64 `default_rng(seed: 0).choice(54_000, count, replace: false)`. Compiling
/// them into Smelt removes a Python/NumPy runtime dependency while retaining
/// candidate order. FPS starts at candidate zero and keeps the first argmax tie.
public enum SmeltPointSelector {
    public static func select(
        pointNormals: [Float],
        projection: SmeltPointProjection
    ) throws -> SmeltPointSelection {
        guard pointNormals.count == 54_000 * 6 else {
            throw SmeltPointSelectionError.invalidPointNormalCount(
                pointNormals.count
            )
        }
        guard pointNormals.allSatisfy(\.isFinite) else {
            throw SmeltPointSelectionError.nonFinitePointNormal
        }
        let candidates: [Int]
        let outputCount: Int
        switch projection {
        case .mesh:
            candidates = decodeUInt32(meshCandidatesBase64, expectedCount: 2_048)
            outputCount = 512
        case .condition:
            candidates = decodeUInt32(conditionCandidatesBase64, expectedCount: 1_536)
            outputCount = 384
        }
        let indices = farthestPointSourceIndices(
            pointNormals: pointNormals,
            candidates: candidates,
            outputCount: outputCount
        )
        var selected = [Float]()
        selected.reserveCapacity(outputCount * 6)
        for sourceIndex in indices {
            selected.append(
                contentsOf: pointNormals[(sourceIndex * 6)..<(sourceIndex * 6 + 6)]
            )
        }
        return SmeltPointSelection(sourceIndices: indices, pointNormals: selected)
    }

    static func farthestPointSourceIndices(
        pointNormals: [Float],
        candidates: [Int],
        outputCount: Int
    ) -> [Int] {
        precondition(!candidates.isEmpty && outputCount > 0 && outputCount <= candidates.count)
        var minimumDistances = [Float](repeating: .infinity, count: candidates.count)
        var selected = [Int]()
        selected.reserveCapacity(outputCount)
        var farthest = 0
        for _ in 0..<outputCount {
            let centroidIndex = candidates[farthest] * 6
            let centerX = pointNormals[centroidIndex]
            let centerY = pointNormals[centroidIndex + 1]
            let centerZ = pointNormals[centroidIndex + 2]
            selected.append(candidates[farthest])
            for candidatePosition in candidates.indices {
                let pointIndex = candidates[candidatePosition] * 6
                let dx = pointNormals[pointIndex] - centerX
                let dy = pointNormals[pointIndex + 1] - centerY
                let dz = pointNormals[pointIndex + 2] - centerZ
                let distance = dx * dx + dy * dy + dz * dz
                minimumDistances[candidatePosition] = min(
                    minimumDistances[candidatePosition],
                    distance
                )
            }
            farthest = 0
            var maximumDistance = minimumDistances[0]
      for candidatePosition in minimumDistances.indices.dropFirst()
      where
                minimumDistances[candidatePosition] > maximumDistance
            {
                maximumDistance = minimumDistances[candidatePosition]
                farthest = candidatePosition
            }
        }
        return selected
    }

    private static func decodeUInt32(_ encoded: String, expectedCount: Int) -> [Int] {
        guard let data = Data(base64Encoded: encoded, options: .ignoreUnknownCharacters),
              data.count == expectedCount * MemoryLayout<UInt32>.stride
        else {
      preconditionFailure("corrupt compiled skinning component candidate table")
        }
        return data.withUnsafeBytes { bytes in
            (0..<expectedCount).map { index in
                Int(
                    bytes.loadUnaligned(
                        fromByteOffset: index * 4,
                        as: UInt32.self
                    ).littleEndian
                )
            }
        }
    }

    private static let meshCandidatesBase64 =
        ""
    private static let conditionCandidatesBase64 =
        ""
}

public enum SmeltPointSelectionError: Error, Equatable {
    case invalidPointNormalCount(Int)
    case nonFinitePointNormal
}
